<?php

namespace Drush\Commands\example;

use Drush\Attributes as CLI;
use Drush\Commands\DrushCommands;

final class ExampleCommand extends DrushCommands {
  public function __construct(
    private \Drupal\Core\Entity\EntityTypeManagerInterface $entityTypeManager
  ) {
  }

  /**
   * Create a new example entity.
   */
  #[CLI\Command(name: 'example:create', aliases: ['ex-cre'])]
  #[CLI\Argument(name: 'machine_name', description: 'The machine name of the example entity.')]
  #[CLI\Option(name: 'status', description: 'Initial status (1 = published, 0 = unpublished).', valueType: 'int', default: 1)]
  public function create(string $machine_name, array $options = ['status' => 1]): void {
    $this->io()->success("Creating example entity '$machine_name' with status {$options['status']}.");

    // Example usage of injected service
    $storage = $this->entityTypeManager->getStorage('example_entity');
    $entity = $storage->create([
      'uuid' => $this->generateUuid(),
      'id' => $machine_name,
      'status' => (bool) $options['status'],
    ]);
    $entity->save();

    $this->io()->table(
      ['Field', 'Value'],
      [['ID', $entity->id()], ['UUID', $entity->uuid()], ['Status', $entity->status ? 'published' : 'unpublished']]
    );
