      $this->logger()->info('Verbose mode enabled for target {target}', ['{target}' => $target]);
    }

    $results = $this->fetchResults($target);

    $this->io()->success('Generated {count} records for {target}', [
      '{count}' => count($results),
      '{target}' => $target,
    ]);

    $table = [
      ['ID', 'Title', 'Status'],
    ];
    foreach ($results as $item) {
      $table[] = [$item['id'], $item['title'], $item['status']];
    }
    $this->io()->table(['ID', 'Title', 'Status'], $table);

    return self::SUCCESS;
  }

  private function fetchResults(string $target): array {
    // Simulate fetching data — replace with real logic (e.g., entity queries)
    return [
      ['id' => 1, 'title' => 'Item A', 'status' => 'active'],
      ['id' => 2, 'title' => 'Item B', 'status' => 'pending'],
    ];
  }
}
```

