    }
}
```

**Example 2: Nested subnamespace (e.g., per-contrib module)**
```json
// composer.json
{
  "autoload": {
    "psr-4": {
      "Drush\\Commands\\contrib\\my_module\\": "src/"
    }
  }
}
```

```php
